#include <stdio.h>
#include <math.h>
#define MOD 1000000007
long long gcd(long long a, long long b) { return b == 0 ? a : gcd(b, a % b); }
long long lcm(long long a, long long b) { return (a * b) / gcd(a, b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A, B, M;
        scanf("%d %d %d", &A, &B, &M);
        int C[T - 1], D[T - 1];
        for (int i = 0; i < T - 1; i++) {
            scanf("%d", &C[i]);
        }
        for (int i = 0; i < T - 1; i++) {
            scanf("%d", &D[i]);
        }
        long long ans = 1;
        for (int i = 1; i <= K; i++) {
            ans = lcm(ans, (N / i) * i);
            ans %= MOD;
        }
        printf("%lld\n", ans);
        N = (1 + (A * ans + C[0]) % M);
        K = (1 + (B * ans + D[0]) % N);
        for (int i = 1; i < T - 1; i++) {
            ans = 1;
            for (int j = 1; j <= K; j++) {
                ans = lcm(ans, (N / j) * j);
                ans %= MOD;
            }
            printf("%lld\n", ans);
            N = (1 + (A * ans + C[i]) % M);
            K = (1 + (B * ans + D[i]) % N);
        }
    }
    return 0;
}

