        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int A = sc.nextInt();
            int B = sc.nextInt();
            int M = sc.nextInt();
            int[] C = new int[T - 1];
            int[] D = new int[T - 1];
            for (int i = 0; i < T - 1; i++) {
                C[i] = sc.nextInt();
            }
            for (int i = 0; i < T - 1; i++) {
                D[i] = sc.nextInt();
            }
            long ans = 1;
            for (int i = 1; i <= K; i++) {
                ans = lcm(ans, (N / i) * i);
                ans %= 1000000007;
            }
            System.out.println(ans);
            N = (1 + (int)((A * ans + C[0]) % M));
            K = (1 + (int)((B * ans + D[0]) % N));
            for (int i = 1; i < T - 1; i++) {
                ans = 1;
                for (int j = 1; j <= K; j++) {
                    ans = lcm(ans, (N / j) * j);
                    ans %= 1000000007;
                }
                System.out.println(ans);
                N = (1 + (int)((A * ans + C[i]) % M));
                K = (1 + (int)((B * ans + D[i]) % N));
            }
        }
    }
    public static long gcd(long a, long b) {
        return b == 0 ? a : gcd(b, a % b);
    }
    public static long lcm(long a, long b) {
        return (a * b) / gcd(a, b);
    }
}

